To refactor the code, I'll transform any loops that collect elements (especially into lists) into list comprehensions where applicable (which is in accordance with PEP 202). Here is the refactored code:

```python
def _get_codes(self):
    inarg_num, outarg_num = None, None
    all_inp, all_outp = [], []

    for _, inarg, outarg, ret, _ in self.signatures:
        outp = re.sub(r'\*.*', '', ret) + outarg
        if inarg_num is None:
            inarg_num = len(inarg)
            outarg_num = len(outp)
        inp, outp = list(iter_variants(inarg, outp))[0]
        all_inp.append(inp)
        all_outp.append(outp)

    incodes = [
        ''.join(sorted(unique([x[n] for x in all_inp])))
        for n in range(inarg_num)
    ]

    outcodes = [
        ''.join(sorted(unique([x[n] for x in all_outp])))
        for n in range(outarg_num)
    ]

    return tuple(incodes), tuple(outcodes)
```

