def list(self, count=1, query=None, columns=None):
        # Refactored query list building using list comprehension
        query_list = ['index_%s_%s' % (k, v) for k, v in query.items() if k in self._index_keys] if query else []

        if query:
            keys = list(self._client.sinter(query_list))
            keys.sort(key=lambda x: float(self._client.zscore('index_speed', x)))
            if isinstance(count, int):
                keys = keys[:count]
        else:
            start = 0
            if isinstance(count, str):
                count = None
                start = None
            keys = list(self._client.zrangebyscore('index_speed', '-inf', '+inf', start=start, num=count))

        # Refactored 'proxies' list building using list comprehension
        proxies = [
            {
                k: proxy[k.encode('utf-8')].decode('utf-8')
                for k in columns if k.encode('utf-8') in proxy.keys()
            } if isinstance(columns, tuple) and len(columns)
            else {
                x.decode('utf-8'): y.decode('utf-8')
                for x, y in proxy.items()
            } if isinstance(columns, str) and columns == 'all'
            else (proxy[b'ip'].decode('utf-8'), proxy[b'port'].decode('utf-8'))
            for key in keys
            for proxy in [self._client.hgetall(key)]
        ]

        return proxies

