def verify_equivs(ann_obj, projectconf):
    issues = []

    # shortcut
    def disp(s):
        return projectconf.preferred_display_form(s)

    for eq in ann_obj.get_equivs():
        # get the equivalent annotations using list comprehension
        equiv_anns = [ann_obj.get_ann_by_id(eid) for eid in eq.entities]

        # all pairs of entity types in the Equiv group must be allowed
        eq_type = {e.type: True for e in equiv_anns}

        # create type pairs using list comprehension
        type_pairs = [(t1, t2) for t1 in eq_type for t2 in eq_type]

        # do avoid marking both (a1,a2) and (a2,a1), remember what's already included
        marked = {}

        for t1, t2 in type_pairs:
            reltypes = projectconf.relation_types_from_to(t1, t2)

            # check if any of the reltypes is an equivalent type using any()
            equiv_type_found = any(projectconf.is_equiv_type(rt) for rt in reltypes)

            if not equiv_type_found:
                # Avoid redundant output
                if (t2, t1) in marked:
                    continue

                # TODO: mark this error on the Eq relation, not the entities
                issues.extend(
                    AnnotationIssue(
                        e.id, AnnotationError, "Equivalence relation %s not allowed between %s and %s" %
                        (eq.type, disp(t1), disp(t2))
                    ) for e in equiv_anns
                )
                marked[(t1, t2)] = True

    return issues

